func defaultReloadStatus() reloadStatus {
	return reloadStatus{
		ErrorCategory:     errorCategoryNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMs: map[string]int64{},
	}
}

// reloadStatusTracker owns the last observed reload outcome, the last
// known-good configuration used for rollback, and (de)serialization of the
// outcome to disk. It is safe to use even when transactional reload is
// disabled: in that case it simply keeps serving the default status and
// never persists anything.
type reloadStatusTracker struct {
	enabled     bool
	storagePath string
	logger      *slog.Logger

	mu             sync.RWMutex
	status         reloadStatus
	lastGoodConfig *config.Config
}

func newReloadStatusTracker(enabled bool, storagePath string, logger *slog.Logger) *reloadStatusTracker {
	t := &reloadStatusTracker{
		enabled:     enabled,
		storagePath: storagePath,
		logger:      logger,
		status:      defaultReloadStatus(),
	}
	if enabled {
		t.status = t.load()
	}
	return t
}

// Get returns the most recently observed reload outcome.
func (t *reloadStatusTracker) Get() reloadStatus {
	t.mu.RLock()
	defer t.mu.RUnlock()
	return t.status
}

func (t *reloadStatusTracker) setLastGoodConfig(conf *config.Config) {
	t.mu.Lock()
	defer t.mu.Unlock()
	t.lastGoodConfig = conf
}

func (t *reloadStatusTracker) getLastGoodConfig() *config.Config {
	t.mu.RLock()
	defer t.mu.RUnlock()
	return t.lastGoodConfig
}

// recordOutcome stores and persists the outcome of a real reload attempt
// (triggered via SIGHUP, the /-/reload endpoint, or the auto-reload ticker).
// It must not be called for the initial configuration load performed at
// startup, which is not considered a "reload attempt".
func (t *reloadStatusTracker) recordOutcome(s reloadStatus) {
	if s.AppliedReloaders == nil {
		s.AppliedReloaders = []string{}
	}
	if s.ReloaderTimingsMs == nil {
		s.ReloaderTimingsMs = map[string]int64{}
	}

	t.mu.Lock()
	t.status = s
	t.mu.Unlock()

	if err := t.persist(s); err != nil {
		t.logger.Error("Failed to persist reload status", "err", err)
	}
}

func newReloadID() string {
	return time.Now().UTC().Format(time.RFC3339)
}

func (t *reloadStatusTracker) statePath() string {
	if t.storagePath == "" {
		return ""
	}
	return filepath.Join(t.storagePath, reloadStatusFilename)
}

// persist atomically writes the given status to disk via a temp-file-then-rename,
// matching the pattern used elsewhere in the codebase (e.g. tsdb block meta files).
func (t *reloadStatusTracker) persist(s reloadStatus) error {
	path := t.statePath()
	if path == "" {
		return nil
	}

	data, err := json.MarshalIndent(s, "", "  ")
	if err != nil {
		return err
	}

	tmp := path + ".tmp"
	f, err := os.Create(tmp)
	if err != nil {
		return err
	}
	defer os.RemoveAll(tmp)

	if _, err := f.Write(data); err != nil {
		f.Close()
		return err
	}
	if err := f.Sync(); err != nil {
		f.Close()
		return err
	}
	if err := f.Close(); err != nil {
		return err
	}
	return fileutil.Replace(tmp, path)
}

// load reads a persisted reload status from disk. Missing or corrupted
// state must not prevent startup, so any error simply results in the
// default (pre-first-reload) status being returned.
func (t *reloadStatusTracker) load() reloadStatus {
	path := t.statePath()
	if path == "" {
		return defaultReloadStatus()
	}

	data, err := os.ReadFile(path)
	if err != nil {
		if !os.IsNotExist(err) {
			t.logger.Warn("Failed to read persisted reload status, starting with default status", "err", err)
		}
		return defaultReloadStatus()
	}

